"use strict";(self.webpackChunkwoodpecker=self.webpackChunkwoodpecker||[]).push([["3729"],{44227(e){e.exports=JSON.parse('{"name":"Laravel Forge","slug":"laravel-forge","url":"https://github.com/njaaazi/laravel-forge-woodpecker","description":"Trigger a Laravel Forge deployment from Woodpecker CI","docs":"<h1>Overview</h1>\\n<p>Woodpecker CI plugin that triggers a <a href=\\"https://forge.laravel.com\\">Laravel Forge</a> deployment.</p>\\n<p>Heavily based on <a href=\\"https://github.com/jbrooksuk/laravel-forge-action\\"><code>jbrooksuk/laravel-forge-action</code></a>.</p>\\n<h2>Settings</h2>\\n<table>\\n<thead>\\n<tr>\\n<th>Settings Name</th>\\n<th>Default</th>\\n<th>Description</th>\\n</tr>\\n</thead>\\n<tbody><tr>\\n<td><code>trigger_url</code></td>\\n<td><em>none</em></td>\\n<td>Forge deployment trigger URL. Found in your site\'s detail panel in Forge.</td>\\n</tr>\\n<tr>\\n<td><code>api_key</code></td>\\n<td><em>none</em></td>\\n<td>Forge API key. Generate one at <a href=\\"https://forge.laravel.com/user-profile/api\\">https://forge.laravel.com/user-profile/api</a>. Requires <code>server_id</code> and <code>site_id</code>.</td>\\n</tr>\\n<tr>\\n<td><code>server_id</code></td>\\n<td><em>none</em></td>\\n<td>Forge server ID. Found in the server\'s detail panel.</td>\\n</tr>\\n<tr>\\n<td><code>site_id</code></td>\\n<td><em>none</em></td>\\n<td>Forge site ID. Found in the site\'s detail panel.</td>\\n</tr>\\n<tr>\\n<td><code>query</code></td>\\n<td><em>none</em></td>\\n<td>Optional. Extra query string appended to <code>trigger_url</code> (e.g. <code>tag=v1.0.0</code>). Do not include a leading <code>?</code>.</td>\\n</tr>\\n</tbody></table>\\n<p>If both <code>trigger_url</code> and <code>api_key</code> are set, <code>trigger_url</code> takes precedence. It is highly recommended to store all settings using <a href=\\"https://woodpecker-ci.org/docs/usage/secrets\\">Woodpecker secrets</a>.</p>\\n<h2>Examples</h2>\\n<h3>Trigger URL mode</h3>\\n<pre><code class=\\"language-yaml\\">steps:\\n  deploy:\\n    image: njaaazi/laravel-forge-woodpecker:latest\\n    settings:\\n      trigger_url:\\n        from_secret: forge_trigger_url\\n    when:\\n      - branch: main\\n        event: push\\n</code></pre>\\n<p>Pass extra query params (e.g. a tag) via <code>query</code>:</p>\\n<pre><code class=\\"language-yaml\\">steps:\\n  deploy:\\n    image: njaaazi/laravel-forge-woodpecker:latest\\n    settings:\\n      trigger_url:\\n        from_secret: forge_trigger_url\\n      query: \\"tag=${CI_COMMIT_TAG}\\"\\n    when:\\n      - event: tag\\n</code></pre>\\n<h3>API mode</h3>\\n<pre><code class=\\"language-yaml\\">steps:\\n  deploy:\\n    image: njaaazi/laravel-forge-woodpecker:latest\\n    settings:\\n      api_key:\\n        from_secret: forge_api_key\\n      server_id:\\n        from_secret: forge_server_id\\n      site_id:\\n        from_secret: forge_site_id\\n    when:\\n      - branch: main\\n        event: push\\n</code></pre>\\n","tags":["deploy","laravel","forge"],"author":"Njazi Shehu","containerImage":"njaaazi/laravel-forge-woodpecker","verified":false}')}}]);